const SAVE_KEY = "maseki_artes_like_v40";
const $ = id => document.getElementById(id);
const fmt = n => Math.floor(n||0).toLocaleString("ja-JP");
function baseMember(i){return {id:"m"+i,name:["ソラ","ナギ","ルナ","レイ","ミオ"][i],lv:1,exp:0,next:120,race:DATA.races[i%DATA.races.length].id,job:DATA.jobs[i%DATA.jobs.length].id,title:DATA.titles[i%DATA.titles.length].id,equip:{weapon:null,armor:null,acc:null,relic:null},hp:120,mp:40,atk:25,def:18,spd:10,skills:["basic"]};}
let state = {gold:800,stones:0,floor:1,dungeon:"grass",running:false,party:[0,1,2,3,4].map(baseMember),inventory:{},loot:[],bossKills:{},codex:{},log:[]};
function fxAdd(a,b){for(const [k,v] of Object.entries(b||{}))a[k]=(a[k]||0)+v;return a}
function by(arr,id){return arr.find(x=>x.id===id)}
function item(id){return DATA.items.find(x=>x.id===id)}
function memberPower(m){let f={};fxAdd(f,by(DATA.races,m.race)?.fx);fxAdd(f,by(DATA.jobs,m.job)?.fx);fxAdd(f,by(DATA.titles,m.title)?.fx);let st={hp:m.hp,mp:m.mp,atk:m.atk,def:m.def,spd:m.spd};for(const id of Object.values(m.equip)){let it=item(id);if(!it)continue;for(const [k,v] of Object.entries(it.stat||{}))st[k]=(st[k]||0)+v;fxAdd(f,it.fx)}st.hp=Math.floor(st.hp*(1+(f.hp||0)));st.mp=Math.floor(st.mp*(1+(f.mp||0)));st.atk=Math.floor(st.atk*(1+(f.atk||0)+(f.damage||0)));st.def=Math.floor(st.def*(1+(f.def||0)));st.spd=Math.floor(st.spd*(1+(f.speed||0)));const power=Math.floor(st.hp*.7+st.mp*.4+st.atk*8+st.def*6+st.spd*12);return{st,fx:f,power}}
function partyPower(){return state.party.reduce((s,m)=>s+memberPower(m).power,0)}
function partyFx(){let f={};for(const m of state.party){fxAdd(f,by(DATA.races,m.race)?.fx);fxAdd(f,by(DATA.jobs,m.job)?.fx);fxAdd(f,by(DATA.titles,m.title)?.fx);for(const id of Object.values(m.equip)){let it=item(id);if(it)fxAdd(f,it.fx)}}return f}
function log(text,cls=""){state.log.unshift({text,cls,t:new Date().toLocaleTimeString()});state.log=state.log.slice(0,120);renderLog()}
function renderLog(){$("log").innerHTML=state.log.map(l=>`<div class="${l.cls}">[${l.t}] ${l.text}</div>`).join("")}
function gainExp(amount){for(const m of state.party){m.exp+=Math.floor(amount*(1+(partyFx().exp||0)));while(m.exp>=m.next){m.exp-=m.next;m.lv++;m.next=Math.floor(m.next*1.23+m.lv*95);m.hp=Math.floor(m.hp*1.13+35);m.mp=Math.floor(m.mp*1.10+12);m.atk=Math.floor(m.atk*1.12+8);m.def=Math.floor(m.def*1.10+6);log(`${m.name} Lv${m.lv}`,"rare")}}}
function randomItem(tierBoost=0){const maxTier=Math.min(22,Math.max(1,Math.floor(state.floor/4)+tierBoost));const pool=DATA.items.filter(i=>i.tier<=maxTier&&!i.bossDrop);return pool[Math.floor(Math.random()*pool.length)]}
function addItem(id,n=1){state.inventory[id]=(state.inventory[id]||0)+n}
function dropLoot(tier=0){const it=randomItem(tier);const rarity=Math.random()<.04?"神話":Math.random()<.14?"伝説":Math.random()<.34?"希少":"通常";state.loot.push({item:it.id,rarity,tier:it.tier});log(`未鑑定品を入手: ${rarity}`,rarity==="神話"?"rare":"good")}
function enemyName(d){const names=["魔狼","星骸兵","古代スライム","黒羽獣","魔導機","竜牙兵","神殿守","亡霊王子"];return d.name+"の"+names[Math.floor(Math.random()*names.length)]}
function exploreStep(){const d=by(DATA.dungeons,state.dungeon),p=partyPower(),fx=partyFx();const danger=Math.floor(d.danger*(1+state.floor*.09)*Math.pow(1.055,state.floor));const metal=Math.random()<((fx.metal||0)+0.001);const actual=metal?Math.floor(danger*.55):danger;const name=metal?"星界メタル":enemyName(d);$("mainBossName").textContent=name;$("mainBossInfo").textContent=`危険度 ${fmt(actual)} / 味方戦力 ${fmt(p)}`;if(metal)$("mainBossImg").src=DATA.bosses.find(b=>b.id==="inv_slime").img;const winRate=Math.max(.08,Math.min(.96,p/(p+actual)));if(Math.random()<winRate){const exp=Math.floor((actual*.22+state.floor*30)*(metal?65:1));const gold=Math.floor(actual*.06*(1+(fx.gold||0)));state.gold+=gold;state.stones+=Math.floor(1+state.floor/8+(fx.absorb||0)*5);gainExp(exp);if(Math.random()<.32+(fx.drop||0))dropLoot(metal?4:0);state.floor++;log(`${name}撃破 EXP${fmt(exp)} / G${fmt(gold)}`,metal?"rare":"good")}else{const loss=Math.max(1,Math.floor(state.gold*.03));state.gold-=loss;log(`${name}に敗北。G-${fmt(loss)}。ビルド再調整が必要`,"bad")}render()}
let timer=null;
function start(){if(timer)return;state.running=true;timer=setInterval(exploreStep,420);log("探索開始","good");render()}
function stop(){if(timer)clearInterval(timer);timer=null;state.running=false;log("探索停止");render()}
function challengeBoss(id){const b=by(DATA.bosses,id);if(!b)return;$("mainBossImg").src=b.img;$("mainBossName").textContent=b.name;$("mainBossInfo").textContent=`${b.race} / ${b.attr}`;const p=partyPower(),level=(state.bossKills[id]||0),pow=Math.floor(b.power*Math.pow(1.42,level));const rate=Math.max(.04,Math.min(.92,p/(p+pow)));if(Math.random()<rate){state.bossKills[id]=(state.bossKills[id]||0)+1;state.stones+=100+level*40;state.gold+=Math.floor(pow*.05);gainExp(Math.floor(pow*.2));for(const it of DATA.items.filter(x=>x.bossDrop===id)){if(Math.random()<.45)addItem(it.id)}log(`${b.name}討伐成功！ ${b.drop} と専用装備を獲得候補`,"rare")}else{log(`${b.name}に敗北。必要戦力: ${fmt(pow)} / 現在: ${fmt(p)}`,"bad")}render()}
function identify(all=false){if(!state.loot.length){log("未鑑定品なし");return}const list=all?state.loot.splice(0):[state.loot.shift()];for(const l of list){addItem(l.item);const it=item(l.item);log(`鑑定: ${l.rarity} ${it.name}`,l.rarity==="神話"||l.rarity==="伝説"?"rare":"good")}render()}
function sellJunk(){let gain=0;for(const [id,n] of Object.entries({...state.inventory})){const it=item(id);if(it&&it.tier<=3&&n>1){const sell=n-1;state.inventory[id]=1;gain+=sell*Math.floor(it.price*.35)}}state.gold+=gain;log(`低Tier余剰装備を売却 G+${fmt(gain)}`,"good");render()}
function buy(id){const it=item(id);if(!it)return;if(state.gold<it.price){log("Gold不足","bad");return}state.gold-=it.price;addItem(id);log(`${it.name}購入`,"good");render()}
function equip(mid,id){const m=state.party[mid],it=item(id);if(!m||!it||!state.inventory[id])return;m.equip[it.slot]=id;log(`${m.name}が${it.name}を装備`,"good");render()}
function save(){localStorage.setItem(SAVE_KEY,JSON.stringify(state));log("保存しました","good")}
function load(){const s=localStorage.getItem(SAVE_KEY);if(s){state=JSON.parse(s);stop();log("読み込みました","good");render()}}
function reset(){if(confirm("初期化しますか？")){localStorage.removeItem(SAVE_KEY);location.reload()}}
function rows(obj){return `<div class="buildRows">`+Object.entries(obj).map(([k,v])=>`<div><b>${k}</b><br>${v}</div>`).join("")+`</div>`}
function render(){const d=by(DATA.dungeons,state.dungeon);$("floorText").textContent=fmt(state.floor);$("powerText").textContent=fmt(partyPower());$("goldText").textContent=fmt(state.gold);$("stoneText").textContent=fmt(state.stones);$("lootText").textContent=fmt(state.loot.length);$("dungeonInfo").innerHTML=rows({"最低Lv":d.min,"基礎危険度":fmt(d.danger),"現在危険度":fmt(Math.floor(d.danger*Math.pow(1.055,state.floor))),"探索状態":state.running?"探索中":"停止"});renderParty();renderEquip();renderLoot();renderBoss();renderCodex();if(!$("mainBossImg").src||$("mainBossImg").src.endsWith("/"))$("mainBossImg").src=DATA.bosses[0].img}
function renderParty(){$("partyPanel").innerHTML=`<div class="partyGrid">`+state.party.map((m,i)=>{const mp=memberPower(m);return `<div class="card member"><h3>${m.name} <span class="lv">Lv${m.lv}</span></h3><div class="bars"><div class="bar"><div class="fill" style="width:${Math.min(100,m.exp/m.next*100)}%"></div></div></div><label>種族<select data-edit="race" data-i="${i}">${DATA.races.map(x=>`<option value="${x.id}" ${x.id===m.race?"selected":""}>${x.name}</option>`).join("")}</select></label><label>職業<select data-edit="job" data-i="${i}">${DATA.jobs.map(x=>`<option value="${x.id}" ${x.id===m.job?"selected":""}>${x.name}</option>`).join("")}</select></label><label>二つ名<select data-edit="title" data-i="${i}">${DATA.titles.map(x=>`<option value="${x.id}" ${x.id===m.title?"selected":""}>${x.name}</option>`).join("")}</select></label>${rows({"戦力":fmt(mp.power),"HP":fmt(mp.st.hp),"MP":fmt(mp.st.mp),"攻撃":fmt(mp.st.atk),"防御":fmt(mp.st.def),"速度":fmt(mp.st.spd)})}</div>`}).join("")+`</div>`}
function renderEquip(){const mid=+$("memberSelect").value||0,slot=$("slotSelect").value||"weapon",filter=$("filterSelect").value||"owned";const m=state.party[mid];let list=DATA.items.filter(it=>it.slot===slot);if(filter==="owned")list=list.filter(it=>state.inventory[it.id]);if(filter==="shop")list=list.filter(it=>it.price>0&&!it.bossDrop);if(filter==="boss")list=list.filter(it=>it.bossDrop);list=list.slice(0,220);$("equipPanel").innerHTML=`<div class="equipList">`+list.map(it=>{const own=state.inventory[it.id]||0,eq=m.equip[it.slot]===it.id;return `<div class="card item ${eq?"equipped":""}"><img src="${it.icon}"><div><h3>${it.name} ${eq?"【装備中】":own?"×"+own:""}</h3><span class="tag">Tier${it.tier}</span><span class="tag">${it.slot}</span><p>${Object.entries(it.stat||{}).map(([k,v])=>k+"+"+fmt(v)).join(" / ")}</p><div class="actions">${it.price>0?`<button data-buy="${it.id}">購入 ${fmt(it.price)}G</button>`:""}<button data-equip="${it.id}" ${own?"":"disabled"}>装備</button></div></div></div>`}).join("")+`</div>`}
function renderLoot(){$("lootPanel").innerHTML=`<div class="lootList">`+state.loot.slice(0,90).map(l=>`<div class="card"><h3>${l.rarity}の未鑑定品</h3><p>推定Tier ${l.tier}</p></div>`).join("")+`</div>`}
function renderBoss(){$("bossPanel").innerHTML=`<div class="bossList">`+DATA.bosses.map(b=>{const kills=state.bossKills[b.id]||0,pow=Math.floor(b.power*Math.pow(1.42,kills));return `<div class="card bossCard ${kills?"cleared":""}"><img src="${b.img}"><h3>${b.name}</h3><span class="tag">${b.race}</span><span class="tag">${b.attr}</span>${rows({"討伐":kills,"必要戦力":fmt(pow),"固有素材":b.drop,"固有技":b.skill})}<button data-boss="${b.id}">挑戦</button></div>`}).join("")+`</div>`}
function renderCodex(){$("codexPanel").innerHTML=`<div class="codexGrid">`+DATA.bosses.map(b=>`<div class="card bossCard"><img src="${b.img}"><h3>${b.name}</h3><p>${b.race} / ${b.attr}<br>討伐数: ${state.bossKills[b.id]||0}<br>素材: ${b.drop}<br>技: ${b.skill}</p></div>`).join("")+`</div>`}
document.addEventListener("click",e=>{const t=e.target;if(t.classList.contains("tab")){document.querySelectorAll(".tab").forEach(x=>x.classList.remove("active"));document.querySelectorAll(".panel").forEach(x=>x.classList.remove("active"));t.classList.add("active");$(t.dataset.tab).classList.add("active");render()}if(t.id==="startBtn")start();if(t.id==="stopBtn")stop();if(t.id==="stepBtn")exploreStep();if(t.id==="saveBtn")save();if(t.id==="loadBtn")load();if(t.id==="resetBtn")reset();if(t.id==="identifyOne")identify(false);if(t.id==="identifyAll")identify(true);if(t.id==="sellJunk")sellJunk();if(t.dataset.buy)buy(t.dataset.buy);if(t.dataset.equip)equip(+$("memberSelect").value||0,t.dataset.equip);if(t.dataset.boss)challengeBoss(t.dataset.boss)});
document.addEventListener("change",e=>{const t=e.target;if(t.id==="dungeonSelect"){state.dungeon=t.value;log("探索先を変更: "+by(DATA.dungeons,t.value).name);render()}if(t.id==="memberSelect"||t.id==="slotSelect"||t.id==="filterSelect")renderEquip();if(t.dataset.edit){state.party[+t.dataset.i][t.dataset.edit]=t.value;render()}});
function init(){$("dungeonSelect").innerHTML=DATA.dungeons.map(d=>`<option value="${d.id}">${d.name}</option>`).join("");$("memberSelect").innerHTML=state.party.map((m,i)=>`<option value="${i}">${m.name}</option>`).join("");$("dungeonSelect").value=state.dungeon;if(Object.keys(state.inventory).length===0){for(const it of DATA.items.filter(i=>i.tier<=1))addItem(it.id);state.party.forEach((m,i)=>{["weapon","armor","acc","relic"].forEach(sl=>{let it=DATA.items.find(x=>x.slot===sl&&x.tier===1);if(it)m.equip[sl]=it.id})})}log("v4.0 起動。編成して探索へ送り出してください。","rare");render()}
init();
